}
</style>
<defs>
        ${commonDefs(p, cloudD)}
        <path id="${p}-cloud-shape" d="${cloudD}"/>
      </defs>
      <!-- cloudling 在灯下面 (先渲染, 灯后渲染压在上面) -->
      <g class="scene" transform="translate(${f.cloudTx.toFixed(3)} ${f.cloudTy.toFixed(3)}) rotate(${f.cloudRot.toFixed(3)} 12 12)">
        <g class="squash" transform="translate(12 ${squashOY}) scale(${f.cloudScaleX.toFixed(4)} ${f.cloudScaleY.toFixed(4)}) translate(-12 ${(-squashOY).toFixed(3)})">
          <g class="breath" transform="translate(12 12) scale(${f.breathScale.toFixed(4)}) translate(-12 -12)">
            ${cloudling}
            ${hat}
            ${mask}
          </g>
        </g>
      </g>
      <!-- 灯在云宝上面 (云宝顶到灯底, 灯压云宝). v6 去掉拉绳三角坠. -->
      ${lamp}
      ${zHTML}
  `;
}

/* =========================================================================
 * 主循环 + 控件
 * ========================================================================= */
let startT = performance.now();
let elapsedOffset = 0;
let pausedAt = 0;

const scrubberEl = document.getElementById('scrubber');
const tDisplayEl = document.getElementById('t-display');

function getCurrentT() {
  if (scrubbing) return Number(scrubberEl.value);
  if (paused) return elapsedOffset + (pausedAt - startT) / 1000;
  return elapsedOffset + (performance.now() - startT) / 1000;
}

function loop() {
  const t = getCurrentT();
  const T = getTimeline();
  const totalLen = T.tSettleEnd + 5;
  scrubberEl.max = totalLen.toFixed(2);
  if (!scrubbing) scrubberEl.value = Math.min(t, totalLen).toFixed(3);
  tDisplayEl.textContent = `${t.toFixed(2)} s`;
  renderFrame(t);
  requestAnimationFrame(loop);
}
renderFrame(0);
requestAnimationFrame(loop);
